195→func NewLeveledCompactor(ctx context.Context, r prometheus.Registerer, l *slog.Logger, ranges []int64, pool chunkenc.Pool, mergeFunc storage.VerticalChunkSeriesMergeFunc) (*LeveledCompactor, error) {
196→	return NewLeveledCompactorWithOptions(ctx, r, l, ranges, pool, LeveledCompactorOptions{
197→		MergeFunc:                   mergeFunc,
198→		EnableOverlappingCompaction: true,
199→	})
200→}
201→
202→func NewLeveledCompactorWithOptions(ctx context.Context, r prometheus.Registerer, l *slog.Logger, ranges []int64, pool chunkenc.Pool, opts LeveledCompactorOptions) (*LeveledCompactor, error) {
203→	if len(ranges) == 0 {
204→		return nil, errors.New("at least one range must be provided")
205→	}
206→	if pool == nil {
207→		pool = chunkenc.NewPool()
208→	}
209→	if l == nil {
210→		l = promslog.NewNopLogger()
211→	}
212→	mergeFunc := opts.MergeFunc
213→	if mergeFunc == nil {
214→		mergeFunc = storage.NewCompactingChunkSeriesMerger(storage.ChainedSeriesMerge)
215→	}
216→	maxBlockChunkSegmentSize := opts.MaxBlockChunkSegmentSize
217→	if maxBlockChunkSegmentSize == 0 {
218→		maxBlockChunkSegmentSize = chunks.DefaultChunkSegmentSize
219→	}
220→	pe := opts.PE
221→	if pe == nil {
222→		pe = index.EncodePostingsRaw
223→	}
224→	if opts.Metrics == nil {
225→		opts.Metrics = NewCompactorMetrics(r)
226→	}
227→	return &LeveledCompactor{
228→		ranges:                      ranges,
229→		chunkPool:                   pool,
230→		logger:                      l,
231→		metrics:                     opts.Metrics,
232→		ctx:                         ctx,
233→		maxBlockChunkSegmentSize:    maxBlockChunkSegmentSize,
234→		useUncachedIO:               opts.UseUncachedIO,
235→		mergeFunc:                   mergeFunc,
236→		postingsEncoder:             pe,
237→		postingsDecoderFactory:      opts.PD,
238→		enableOverlappingCompaction: opts.EnableOverlappingCompaction,
239→		blockExcludeFunc:            opts.BlockExcludeFilter,
240→	}, nil
241→}
242→
243→type dirMeta struct {
244→	dir  string
245→	meta *BlockMeta
246→}
247→
248→// Plan returns a list of compactable blocks in the provided directory.
249→func (c *LeveledCompactor) Plan(dir string) ([]string, error) {
250→	dirs, err := blockDirs(dir)
251→	if err != nil {
252→		return nil, err
253→	}
254→	if len(dirs) < 1 {
255→		return nil, nil
256→	}
257→
258→	var dms []dirMeta
259→	for _, dir := range dirs {
260→		meta, _, err := readMetaFile(dir)
261→		if err != nil {
262→			return nil, err
263→		}
264→		if c.blockExcludeFunc != nil && c.blockExcludeFunc(meta) {
265→			// Compactions work from oldest to newest, uploads do the same (usually).
266→			// If you continue here you'll skip compactions on this one block, but:
267→			// * all further blocks are NOT yet uploaded
268→			// * some or all further blocks are uploaded
269→			//
270→			// If we continue and there are newer blocks to pick from,
271→			// then you will compact in a non-continuous way, leaving gaps of individual un-compacted blocks.
272→			break
273→		}
274→		dms = append(dms, dirMeta{dir, meta})
275→	}
276→	return c.plan(dms)
277→}
278→
279→func (c *LeveledCompactor) plan(dms []dirMeta) ([]string, error) {
280→	if len(dms) == 0 {
281→		return nil, nil
282→	}
283→
284→	slices.SortFunc(dms, func(a, b dirMeta) int {
285→		switch {
286→		case a.meta.MinTime < b.meta.MinTime:
287→			return -1
288→		case a.meta.MinTime > b.meta.MinTime:
289→			return 1
290→		default:
291→			return 0
292→		}
293→	})
294→
295→	res := c.selectOverlappingDirs(dms)
296→	if len(res) > 0 {
297→		return res, nil
298→	}
299→	// No overlapping blocks, do compaction the usual way.
300→	// We do not include a recently created block with max(minTime), so the block which was just created from WAL.
301→	// This gives users a window of a full block size to piece-wise backup new data without having to care about data overlap.
302→	dms = dms[:len(dms)-1]
303→
304→	for _, dm := range c.selectDirs(dms) {
305→		res = append(res, dm.dir)
306→	}
307→	if len(res) > 0 {
308→		return res, nil
309→	}
310→
311→	// Compact any blocks with big enough time range that have >5% tombstones.
312→	for i := len(dms) - 1; i >= 0; i-- {
313→		meta := dms[i].meta
314→		if meta.MaxTime-meta.MinTime < c.ranges[len(c.ranges)/2] {
315→			// If the block is entirely deleted, then we don't care about the block being big enough.
316→			// TODO: This is assuming a single tombstone is for a distinct series, which might not be true.
317→			if meta.Stats.NumTombstones > 0 && meta.Stats.NumTombstones >= meta.Stats.NumSeries {
318→				return []string{dms[i].dir}, nil
319→			}
320→			break
321→		}
322→		if float64(meta.Stats.NumTombstones)/float64(meta.Stats.NumSeries+1) > 0.05 {
323→			return []string{dms[i].dir}, nil
324→		}
325→	}
326→
327→	return nil, nil
328→}
329→
330→// selectDirs returns the dir metas that should be compacted into a single new block.
331→// If only a single block range is configured, the result is always nil.
332→func (c *LeveledCompactor) selectDirs(ds []dirMeta) []dirMeta {
333→	if len(c.ranges) < 2 || len(ds) < 1 {
334→		return nil
335→	}
336→
337→	highTime := ds[len(ds)-1].meta.MinTime
338→
339→	for _, iv := range c.ranges[1:] {
340→		parts := splitByRange(ds, iv)
341→		if len(parts) == 0 {
342→			continue
343→		}
344→
345→	Outer:
346→		for _, p := range parts {
347→			// Do not select the range if it has a block whose compaction failed.
348→			for _, dm := range p {
349→				if dm.meta.Compaction.Failed {
350→					continue Outer
351→				}
352→			}
353→
354→			mint := p[0].meta.MinTime
355→			maxt := p[len(p)-1].meta.MaxTime
356→			// Pick the range of blocks if it spans the full range (potentially with gaps)
357→			// or is before the most recent block.
358→			// This ensures we don't compact blocks prematurely when another one of the same
359→			// size still fits in the range.
360→			if (maxt-mint == iv || maxt <= highTime) && len(p) > 1 {
361→				return p
362→			}
363→		}
364→	}
365→
366→	return nil
367→}
368→
369→// selectOverlappingDirs returns all dirs with overlapping time ranges.
370→// It expects sorted input by mint and returns the overlapping dirs in the same order as received.
371→func (c *LeveledCompactor) selectOverlappingDirs(ds []dirMeta) []string {
372→	if !c.enableOverlappingCompaction {
373→		return nil
374→	}
375→	if len(ds) < 2 {
376→		return nil
377→	}
378→	var overlappingDirs []string
379→	globalMaxt := ds[0].meta.MaxTime
380→	for i, d := range ds[1:] {
381→		if d.meta.MinTime < globalMaxt {
382→			if len(overlappingDirs) == 0 { // When it is the first overlap, need to add the last one as well.
383→				overlappingDirs = append(overlappingDirs, ds[i].dir)
384→			}
385→			overlappingDirs = append(overlappingDirs, d.dir)
386→		} else if len(overlappingDirs) > 0 {
387→			break
388→		}
389→		if d.meta.MaxTime > globalMaxt {
390→			globalMaxt = d.meta.MaxTime
391→		}
392→	}
393→	return overlappingDirs
394→}
395→
396→// splitByRange splits the directories by the time range. The range sequence starts at 0.
397→//
398→// For example, if we have blocks [0-10, 10-20, 50-60, 90-100] and the split range tr is 30
399→// it returns [0-10, 10-20], [50-60], [90-100].
400→func splitByRange(ds []dirMeta, tr int64) [][]dirMeta {
401→	var splitDirs [][]dirMeta
402→
403→	for i := 0; i < len(ds); {
404→		var (
405→			group []dirMeta
406→			t0    int64
407→			m     = ds[i].meta
408→		)
409→		// Compute start of aligned time range of size tr closest to the current block's start.
410→		if m.MinTime >= 0 {
411→			t0 = tr * (m.MinTime / tr)
412→		} else {
413→			t0 = tr * ((m.MinTime - tr + 1) / tr)
414→		}
415→		// Skip blocks that don't fall into the range. This can happen via mis-alignment or
416→		// by being a multiple of the intended range.
417→		if m.MaxTime > t0+tr {
418→			i++
419→			continue
420→		}
421→
422→		// Add all dirs to the current group that are within [t0, t0+tr].
423→		for ; i < len(ds); i++ {
424→			// Either the block falls into the next range or doesn't fit at all (checked above).
425→			if ds[i].meta.MaxTime > t0+tr {
426→				break
427→			}
428→			group = append(group, ds[i])
429→		}
430→
431→		if len(group) > 0 {
432→			splitDirs = append(splitDirs, group)
433→		}
434→	}
435→
436→	return splitDirs
437→}
