1587→// compactOOO creates a new block per possible block range in the compactor's directory from the OOO Head given.
1588→// Each ULID in the result corresponds to a block in a unique time range.
1589→// The db.cmtx mutex should be held before calling this method.
1590→func (db *DB) compactOOO(dest string, oooHead *OOOCompactionHead) (_ []ulid.ULID, err error) {
