1597→	defer func() {
1598→		if err != nil {
1599→			// Best effort removal of created block on any error.
1600→			for _, uid := range ulids {
1601→				_ = os.RemoveAll(filepath.Join(db.dir, uid.String()))
1602→			}
1603→		}
1604→	}()
1605→
1606→	meta := &BlockMeta{}
1607→	meta.Compaction.SetOutOfOrder()
1608→	for t := blockSize * (oooHeadMint / blockSize); t <= oooHeadMaxt; t += blockSize {
1609→		mint, maxt := t, t+blockSize
1610→		// Block intervals are half-open: [b.MinTime, b.MaxTime). Block intervals are always +1 than the total samples it includes.
1611→		uids, err := db.compactor.Write(dest, oooHead.CloneForTimeRange(mint, maxt-1), mint, maxt, meta)
1612→		if err != nil {
1613→			return nil, err
1614→		}
1615→		ulids = append(ulids, uids...)
1616→	}
1617→
1618→	if len(ulids) == 0 {
1619→		db.logger.Info(
1620→			"compact ooo head resulted in no blocks",
1621→			"duration", time.Since(start),
1622→		)
1623→		return nil, nil
1624→	}
1625→
1626→	db.logger.Info(
1627→		"out-of-order compaction completed",
1628→		"duration", time.Since(start),
1629→		"ulids", fmt.Sprintf("%v", ulids),
1630→	)
1631→	return ulids, nil
1632→}
1633→
1634→// compactHead compacts the given RangeHead.
1635→// The db.cmtx should be held before calling this method.
1636→func (db *DB) compactHead(head *RangeHead) error {
1637→	db.lastHeadCompactionTime = time.Now()
1638→
1639→	uids, err := db.compactor.Write(db.dir, head, head.MinTime(), head.BlockMaxTime(), nil)
1640→	if err != nil {
1641→		return fmt.Errorf("persist head block: %w", err)
1642→	}
1643→
1644→	if err := db.reloadBlocks(); err != nil {
1645→		errs := []error{
1646→			fmt.Errorf("reloadBlocks blocks: %w", err),
1647→		}
1648→		for _, uid := range uids {
1649→			if errRemoveAll := os.RemoveAll(filepath.Join(db.dir, uid.String())); errRemoveAll != nil {
1650→				errs = append(errs, fmt.Errorf("delete persisted head block after failed db reloadBlocks:%s: %w", uid, errRemoveAll))
1651→			}
1652→		}
1653→		return errors.Join(errs...)
1654→	}
1655→	if err = db.head.truncateMemory(head.BlockMaxTime()); err != nil {
1656→		return fmt.Errorf("head memory truncate: %w", err)
1657→	}
1658→
1659→	db.head.RebuildSymbolTable(db.logger)
1660→
1661→	return nil
1662→}
1663→
1664→func (db *DB) CompactStaleHead() (err error) {
1665→	db.cmtx.Lock()
1666→	defer func() {
1667→		db.cmtx.Unlock()
1668→		if err != nil {
1669→			db.metrics.staleSeriesCompactionsFailed.Inc()
1670→		}
1671→	}()
1672→
1673→	db.metrics.staleSeriesCompactionsTriggered.Inc()
1674→
1675→	db.logger.Info("Starting stale series compaction")
1676→	start := time.Now()
1677→
1678→	// We get the stale series reference first because this list can change during the compaction below.
1679→	// It is more efficient and easier to provide an index interface for the stale series when we have a static list.
1680→	staleSeriesRefs, err := db.head.SortedStaleSeriesRefsNoOOOData(context.Background())
1681→	if err != nil {
1682→		return err
1683→	}
1684→	meta := &BlockMeta{}
1685→	meta.Compaction.SetStaleSeries()
1686→	mint, maxt := db.head.opts.ChunkRange*(db.head.MinTime()/db.head.opts.ChunkRange), db.head.MaxTime()
1687→	for ; mint < maxt; mint += db.head.chunkRange.Load() {
1688→		staleHead := NewStaleHead(db.Head(), mint, mint+db.head.chunkRange.Load()-1, staleSeriesRefs)
1689→
1690→		uids, err := db.compactor.Write(db.dir, staleHead, staleHead.MinTime(), staleHead.BlockMaxTime(), meta)
1691→		if err != nil {
1692→			return fmt.Errorf("persist stale head: %w", err)
1693→		}
1694→
1695→		db.logger.Info("Stale series block created", "ulids", fmt.Sprintf("%v", uids), "min_time", mint, "max_time", maxt)
1696→
1697→		if err := db.reloadBlocks(); err != nil {
1698→			errs := []error{fmt.Errorf("reloadBlocks blocks: %w", err)}
1699→			for _, uid := range uids {
1700→				if errRemoveAll := os.RemoveAll(filepath.Join(db.dir, uid.String())); errRemoveAll != nil {
1701→					errs = append(errs, fmt.Errorf("delete persisted stale head block after failed db reloadBlocks:%s: %w", uid, errRemoveAll))
1702→				}
1703→			}
1704→			return errors.Join(errs...)
1705→		}
1706→	}
1707→
1708→	if err := db.head.truncateStaleSeries(staleSeriesRefs, maxt); err != nil {
1709→		return fmt.Errorf("head truncate: %w", err)
1710→	}
1711→	db.head.RebuildSymbolTable(db.logger)
1712→
1713→	elapsed := time.Since(start)
1714→	db.metrics.staleSeriesCompactionDuration.Observe(elapsed.Seconds())
1715→	db.logger.Info("Ending stale series compaction", "num_series", len(staleSeriesRefs), "duration", elapsed)
1716→	return nil
1717→}
1718→
1719→// compactBlocks compacts all the eligible on-disk blocks.
1720→// The db.cmtx should be held before calling this method.
1721→func (db *DB) compactBlocks() (err error) {
1722→	// Check for compactions of multiple blocks.
1723→	for {
1724→		// If we have a lot of blocks to compact the whole process might take
1725→		// long enough that we end up with a HEAD block that needs to be written.
1726→		// Check if that's the case and stop compactions early.
1727→		if db.head.compactable() && !db.waitingForCompactionDelay() {
1728→			db.logger.Warn("aborting block compactions to persist the head block")
1729→			return nil
1730→		}
1731→
1732→		plan, err := db.compactor.Plan(db.dir)
1733→		if err != nil {
1734→			return fmt.Errorf("plan compaction: %w", err)
1735→		}
1736→		if len(plan) == 0 {
1737→			break
1738→		}
1739→
1740→		select {
1741→		case <-db.stopc:
1742→			return nil
1743→		default:
1744→		}
1745→
1746→		uids, err := db.compactor.Compact(db.dir, plan, db.blocks)
1747→		if err != nil {
1748→			return fmt.Errorf("compact %s: %w", plan, err)
1749→		}
1750→
1751→		if err := db.reloadBlocks(); err != nil {
1752→			errs := []error{fmt.Errorf("reloadBlocks blocks: %w", err)}
1753→			for _, uid := range uids {
1754→				if errRemoveAll := os.RemoveAll(filepath.Join(db.dir, uid.String())); errRemoveAll != nil {
1755→					errs = append(errs, fmt.Errorf("delete persisted block after failed db reloadBlocks:%s: %w", uid, errRemoveAll))
1756→				}
1757→			}
1758→			return errors.Join(errs...)
1759→		}
1760→	}
1761→
1762→	return nil
1763→}
