1765→// getBlock iterates a given block range to find a block by a given id.
1766→// If found it returns the block itself and a boolean to indicate that it was found.
1767→func getBlock(allBlocks []*Block, id ulid.ULID) (*Block, bool) {
1768→	for _, b := range allBlocks {
1769→		if b.Meta().ULID == id {
1770→			return b, true
1771→		}
1772→	}
1773→	return nil, false
1774→}
