1776→// reload reloads blocks and truncates the head and its WAL.
1777→// The db.cmtx mutex should be held before calling this method.
1778→func (db *DB) reload() error {
1779→	if err := db.reloadBlocks(); err != nil {
1780→		return fmt.Errorf("reloadBlocks: %w", err)
1781→	}
1782→	maxt, ok := db.inOrderBlocksMaxTime()
1783→	if !ok {
1784→		return nil
1785→	}
1786→	if err := db.head.Truncate(maxt); err != nil {
1787→		return fmt.Errorf("head truncate: %w", err)
1788→	}
1789→	return nil
1790→}
