1792→// reloadBlocks reloads blocks without touching head.
1793→// Blocks that are obsolete due to replacement or retention will be deleted.
1794→// The db.cmtx mutex should be held before calling this method.
1795→func (db *DB) reloadBlocks() (err error) {
1796→	defer func() {
1797→		if err != nil {
1798→			db.metrics.reloadsFailed.Inc()
1799→		}
1800→		db.metrics.reloads.Inc()
1801→	}()
1802→
1803→	db.mtx.RLock()
1804→	loadable, corrupted, err := openBlocks(db.logger, db.dir, db.blocks, db.chunkPool, db.opts.PostingsDecoderFactory)
1805→	db.mtx.RUnlock()
1806→	if err != nil {
1807→		return err
1808→	}
1809→
1810→	deletableULIDs := db.blocksToDelete(loadable)
1811→	deletable := make(map[ulid.ULID]*Block, len(deletableULIDs))
1812→
1813→	// Mark all parents of loaded blocks as deletable (no matter if they exists). This makes it resilient against the process
1814→	// crashing towards the end of a compaction but before deletions. By doing that, we can pick up the deletion where it left off during a crash.
1815→	for _, block := range loadable {
1816→		if _, ok := deletableULIDs[block.meta.ULID]; ok {
1817→			deletable[block.meta.ULID] = block
1818→		}
1819→		for _, b := range block.Meta().Compaction.Parents {
1820→			if _, ok := corrupted[b.ULID]; ok {
1821→				delete(corrupted, b.ULID)
1822→				db.logger.Warn("Found corrupted block, but replaced by compacted one so it's safe to delete. This should not happen with atomic deletes.", "block", b.ULID)
1823→			}
1824→			deletable[b.ULID] = nil
1825→		}
1826→	}
1827→
1828→	if len(corrupted) > 0 {
1829→		// Corrupted but no child loaded for it.
1830→		// Close all new blocks to release the lock for windows.
1831→		db.mtx.RLock()
1832→		for _, block := range loadable {
1833→			if _, open := getBlock(db.blocks, block.Meta().ULID); !open {
1834→				block.Close()
1835→			}
1836→		}
1837→		db.mtx.RUnlock()
1838→		var errs []error
1839→		for ulid, err := range corrupted {
1840→			if err != nil {
1841→				errs = append(errs, fmt.Errorf("corrupted block %s: %w", ulid.String(), err))
1842→			}
1843→		}
1844→		return errors.Join(errs...)
1845→	}
1846→
1847→	var (
1848→		toLoad     []*Block
1849→		blocksSize int64
1850→	)
1851→	// All deletable blocks should be unloaded.
1852→	// NOTE: We need to loop through loadable one more time as there might be loadable ready to be removed (replaced by compacted block).
1853→	for _, block := range loadable {
1854→		if _, ok := deletable[block.Meta().ULID]; ok {
1855→			deletable[block.Meta().ULID] = block
1856→			continue
1857→		}
1858→
1859→		toLoad = append(toLoad, block)
1860→		blocksSize += block.Size()
1861→	}
1862→	db.metrics.blocksBytes.Set(float64(blocksSize))
1863→
1864→	slices.SortFunc(toLoad, func(a, b *Block) int {
1865→		switch {
1866→		case a.Meta().MinTime < b.Meta().MinTime:
1867→			return -1
1868→		case a.Meta().MinTime > b.Meta().MinTime:
1869→			return 1
1870→		default:
1871→			return 0
1872→		}
1873→	})
1874→
1875→	// Swap new blocks first for subsequently created readers to be seen.
1876→	db.mtx.Lock()
1877→	oldBlocks := db.blocks
1878→	db.blocks = toLoad
1879→	db.mtx.Unlock()
1880→
1881→	// Only check overlapping blocks when overlapping compaction is enabled.
1882→	if db.opts.EnableOverlappingCompaction {
1883→		blockMetas := make([]BlockMeta, 0, len(toLoad))
1884→		for _, b := range toLoad {
1885→			blockMetas = append(blockMetas, b.Meta())
1886→		}
1887→		if overlaps := OverlappingBlocks(blockMetas); len(overlaps) > 0 {
1888→			db.logger.Warn("Overlapping blocks found during reloadBlocks", "detail", overlaps.String())
1889→		}
1890→	}
1891→
1892→	// Append blocks to old, deletable blocks, so we can close them.
1893→	for _, b := range oldBlocks {
1894→		if _, ok := deletable[b.Meta().ULID]; ok {
1895→			deletable[b.Meta().ULID] = b
1896→		}
1897→	}
1898→	if err := db.deleteBlocks(deletable); err != nil {
1899→		return fmt.Errorf("delete %v blocks: %w", len(deletable), err)
1900→	}
1901→	return nil
1902→}
1903→
1904→func openBlocks(l *slog.Logger, dir string, loaded []*Block, chunkPool chunkenc.Pool, postingsDecoderFactory PostingsDecoderFactory) (blocks []*Block, corrupted map[ulid.ULID]error, err error) {
1905→	bDirs, err := blockDirs(dir)
1906→	if err != nil {
1907→		return nil, nil, fmt.Errorf("find blocks: %w", err)
1908→	}
1909→
1910→	corrupted = make(map[ulid.ULID]error)
1911→	for _, bDir := range bDirs {
1912→		meta, _, err := readMetaFile(bDir)
1913→		if err != nil {
1914→			l.Error("Failed to read meta.json for a block during reloadBlocks. Skipping", "dir", bDir, "err", err)
1915→			continue
1916→		}
1917→
1918→		// See if we already have the block in memory or open it otherwise.
1919→		block, open := getBlock(loaded, meta.ULID)
1920→		if !open {
1921→			block, err = OpenBlock(l, bDir, chunkPool, postingsDecoderFactory)
1922→			if err != nil {
1923→				corrupted[meta.ULID] = err
1924→				continue
1925→			}
1926→		}
1927→		blocks = append(blocks, block)
1928→	}
1929→	return blocks, corrupted, nil
1930→}
1931→
1932→// DefaultBlocksToDelete returns a filter which decides time based and size based
1933→// retention from the options of the db.
1934→func DefaultBlocksToDelete(db *DB) BlocksToDeleteFunc {
1935→	return func(blocks []*Block) map[ulid.ULID]struct{} {
1936→		return deletableBlocks(db, blocks)
1937→	}
1938→}
1939→
1940→// deletableBlocks returns all currently loaded blocks past retention policy or already compacted into a new block.
1941→func deletableBlocks(db *DB, blocks []*Block) map[ulid.ULID]struct{} {
1942→	deletable := make(map[ulid.ULID]struct{})
1943→
1944→	// Sort the blocks by time - newest to oldest (largest to smallest timestamp).
1945→	// This ensures that the retentions will remove the oldest  blocks.
1946→	slices.SortFunc(blocks, func(a, b *Block) int {
1947→		switch {
1948→		case b.Meta().MaxTime < a.Meta().MaxTime:
1949→			return -1
1950→		case b.Meta().MaxTime > a.Meta().MaxTime:
1951→			return 1
1952→		default:
1953→			return 0
1954→		}
1955→	})
1956→
1957→	for _, block := range blocks {
1958→		if block.Meta().Compaction.Deletable {
1959→			deletable[block.Meta().ULID] = struct{}{}
1960→		}
1961→	}
1962→
1963→	for ulid := range BeyondTimeRetention(db, blocks) {
1964→		deletable[ulid] = struct{}{}
1965→	}
1966→
1967→	for ulid := range BeyondSizeRetention(db, blocks) {
1968→		deletable[ulid] = struct{}{}
1969→	}
1970→
1971→	return deletable
1972→}
1973→
1974→// BeyondTimeRetention returns those blocks which are beyond the time retention
1975→// set in the db options.
1976→func BeyondTimeRetention(db *DB, blocks []*Block) (deletable map[ulid.ULID]struct{}) {
1977→	// Time retention is disabled or no blocks to work with.
1978→	retentionDuration := db.getRetentionDuration()
1979→	if len(blocks) == 0 || retentionDuration == 0 {
1980→		return deletable
1981→	}
1982→
1983→	deletable = make(map[ulid.ULID]struct{})
1984→	for i, block := range blocks {
1985→		// The difference between the first block and this block is greater than or equal to
1986→		// the retention period so any blocks after that are added as deletable.
1987→		if i > 0 && blocks[0].Meta().MaxTime-block.Meta().MaxTime >= retentionDuration {
1988→			for _, b := range blocks[i:] {
1989→				deletable[b.meta.ULID] = struct{}{}
1990→			}
1991→			db.metrics.timeRetentionCount.Inc()
1992→			break
1993→		}
1994→	}
1995→	return deletable
1996→}
1997→
1998→// BeyondSizeRetention returns those blocks which are beyond the size retention
1999→// set in the db options.
2000→func BeyondSizeRetention(db *DB, blocks []*Block) (deletable map[ulid.ULID]struct{}) {
2001→	// No blocks to work with
2002→	if len(blocks) == 0 {
2003→		return deletable
2004→	}
2005→
2006→	maxBytes, maxPercentage := db.getRetentionSettings()
2007→
2008→	// Max percentage prevails over max size.
2009→	if maxPercentage > 0 {
2010→		diskSize := db.fsSizeFunc(db.dir)
2011→		if diskSize <= 0 {
2012→			db.logger.Warn("Unable to retrieve filesystem size of database directory, skip percentage limitation and default to fixed size limitation", "dir", db.dir)
2013→		} else {
2014→			maxBytes = int64(uint64(maxPercentage) * diskSize / 100)
2015→		}
2016→	}
2017→
2018→	// Size retention is disabled.
2019→	if maxBytes <= 0 {
2020→		return deletable
2021→	}
2022→
2023→	deletable = make(map[ulid.ULID]struct{})
2024→
2025→	// Initializing size counter with WAL size and Head chunks
2026→	// written to disk, as that is part of the retention strategy.
2027→	blocksSize := db.Head().Size()
2028→	for i, block := range blocks {
2029→		blocksSize += block.Size()
2030→		if blocksSize > maxBytes {
2031→			// Add this and all following blocks for deletion.
2032→			for _, b := range blocks[i:] {
2033→				deletable[b.meta.ULID] = struct{}{}
2034→			}
2035→			db.metrics.sizeRetentionCount.Inc()
2036→			break
2037→		}
2038→	}
2039→	return deletable
2040→}
2041→
2042→// deleteBlocks closes the block if loaded and deletes blocks from the disk if exists.
2043→// When the map contains a non nil block object it means it is loaded in memory
2044→// so needs to be closed first as it might need to wait for pending readers to complete.
2045→func (db *DB) deleteBlocks(blocks map[ulid.ULID]*Block) error {
2046→	for ulid, block := range blocks {
2047→		if block != nil {
2048→			if err := block.Close(); err != nil {
2049→				db.logger.Warn("Closing block failed", "err", err, "block", ulid)
2050→			}
2051→		}
2052→
2053→		toDelete := filepath.Join(db.dir, ulid.String())
2054→		switch _, err := os.Stat(toDelete); {
2055→		case os.IsNotExist(err):
2056→			// Noop.
2057→			continue
2058→		case err != nil:
2059→			return fmt.Errorf("stat dir %v: %w", toDelete, err)
2060→		}
2061→
2062→		// Replace atomically to avoid partial block when process would crash during deletion.
2063→		tmpToDelete := filepath.Join(db.dir, fmt.Sprintf("%s%s", ulid, tmpForDeletionBlockDirSuffix))
2064→		if err := fileutil.Replace(toDelete, tmpToDelete); err != nil {
2065→			return fmt.Errorf("replace of obsolete block for deletion %s: %w", ulid, err)
2066→		}
2067→		if err := os.RemoveAll(tmpToDelete); err != nil {
2068→			return fmt.Errorf("delete obsolete block %s: %w", ulid, err)
2069→		}
2070→		db.logger.Info("Deleting obsolete block", "block", ulid)
2071→	}
2072→
2073→	return nil
2074→}
2075→
2076→// TimeRange specifies minTime and maxTime range.
2077→type TimeRange struct {
2078→	Min, Max int64
2079→}
2080→
2081→// Overlaps contains overlapping blocks aggregated by overlapping range.
2082→type Overlaps map[TimeRange][]BlockMeta
2083→
2084→// String returns human readable string form of overlapped blocks.
2085→func (o Overlaps) String() string {
2086→	var res []string
2087→	for r, overlaps := range o {
2088→		var groups []string
2089→		for _, m := range overlaps {
2090→			groups = append(groups, fmt.Sprintf(
2091→				"<ulid: %s, mint: %d, maxt: %d, range: %s>",
2092→				m.ULID.String(),
2093→				m.MinTime,
2094→				m.MaxTime,
2095→				(time.Duration((m.MaxTime-m.MinTime)/1000)*time.Second).String(),
2096→			))
2097→		}
2098→		res = append(res, fmt.Sprintf(
2099→			"[mint: %d, maxt: %d, range: %s, blocks: %d]: %s",
2100→			r.Min, r.Max,
2101→			(time.Duration((r.Max-r.Min)/1000)*time.Second).String(),
2102→			len(overlaps),
2103→			strings.Join(groups, ", ")),
2104→		)
2105→	}
2106→	return strings.Join(res, "\n")
2107→}
2108→
2109→// OverlappingBlocks returns all overlapping blocks from given meta files.
2110→func OverlappingBlocks(bm []BlockMeta) Overlaps {
2111→	if len(bm) <= 1 {
2112→		return nil
2113→	}
2114→	var (
2115→		overlaps [][]BlockMeta
2116→
2117→		// pending contains not ended blocks in regards to "current" timestamp.
2118→		pending = []BlockMeta{bm[0]}
2119→		// continuousPending helps to aggregate same overlaps to single group.
2120→		continuousPending = true
2121→	)
2122→
2123→	// We have here blocks sorted by minTime. We iterate over each block and treat its minTime as our "current" timestamp.
2124→	// We check if any of the pending block finished (blocks that we have seen before, but their maxTime was still ahead current
2125→	// timestamp). If not, it means they overlap with our current block. In the same time current block is assumed pending.
2126→	for _, b := range bm[1:] {
2127→		var newPending []BlockMeta
2128→
2129→		for _, p := range pending {
2130→			// "b.MinTime" is our current time.
2131→			if b.MinTime >= p.MaxTime {
2132→				continuousPending = false
2133→				continue
2134→			}
2135→
2136→			// "p" overlaps with "b" and "p" is still pending.
2137→			newPending = append(newPending, p)
2138→		}
2139→
2140→		// Our block "b" is now pending.
2141→		pending = append(newPending, b)
2142→		if len(newPending) == 0 {
2143→			// No overlaps.
2144→			continue
2145→		}
2146→
2147→		if continuousPending && len(overlaps) > 0 {
2148→			overlaps[len(overlaps)-1] = append(overlaps[len(overlaps)-1], b)
2149→			continue
2150→		}
2151→		overlaps = append(overlaps, append(newPending, b))
2152→		// Start new pendings.
2153→		continuousPending = true
2154→	}
2155→
2156→	// Fetch the critical overlapped time range foreach overlap groups.
2157→	overlapGroups := Overlaps{}
2158→	for _, overlap := range overlaps {
2159→		minRange := TimeRange{Min: 0, Max: math.MaxInt64}
2160→		for _, b := range overlap {
2161→			if minRange.Max > b.MaxTime {
2162→				minRange.Max = b.MaxTime
2163→			}
2164→
2165→			if minRange.Min < b.MinTime {
2166→				minRange.Min = b.MinTime
2167→			}
2168→		}
2169→		overlapGroups[minRange] = overlap
2170→	}
2171→
2172→	return overlapGroups
2173→}
