2187→// inOrderBlocksMaxTime returns the max time among the blocks that were not totally created
2188→// out of out-of-order data. If the returned boolean is true, it means there is at least
2189→// one such block.
2190→func (db *DB) inOrderBlocksMaxTime() (maxt int64, ok bool) {
2191→	maxt, ok = int64(math.MinInt64), false
2192→	// If blocks are overlapping, last block might not have the max time. So check all blocks.
2193→	for _, b := range db.Blocks() {
2194→		if !b.meta.Compaction.FromOutOfOrder() && !b.meta.Compaction.FromStaleSeries() && b.meta.MaxTime > maxt {
2195→			ok = true
2196→			maxt = b.meta.MaxTime
2197→		}
2198→	}
2199→	return maxt, ok
2200→}
