2207→// Close the partition.
2208→func (db *DB) Close() error {
2209→	// Allow close-after-close operation for simpler use (e.g. tests).
2210→	select {
2211→	case <-db.donec:
2212→		return nil
2213→	default:
2214→	}
2215→
2216→	close(db.stopc)
2217→	if db.compactCancel != nil {
2218→		db.compactCancel()
2219→	}
2220→	<-db.donec
2221→
2222→	db.mtx.Lock()
2223→	defer db.mtx.Unlock()
2224→
2225→	var g errgroup.Group
2226→
2227→	// blocks also contains all head blocks.
2228→	for _, pb := range db.blocks {
2229→		g.Go(pb.Close)
2230→	}
2231→
2232→	errs := []error{
2233→		g.Wait(),
2234→		db.locker.Release(),
2235→	}
2236→	if db.head != nil {
2237→		errs = append(errs, db.head.Close())
2238→	}
2239→	return errors.Join(errs...)
2240→}
