2269→// Snapshot writes the current data to the directory. If withHead is set to true it
2270→// will create a new block containing all data that's currently in the memory buffer/WAL.
2271→func (db *DB) Snapshot(dir string, withHead bool) error {
2272→	if dir == db.dir {
2273→		return errors.New("cannot snapshot into base directory")
2274→	}
2275→	if _, err := ulid.ParseStrict(dir); err == nil {
2276→		return errors.New("dir must not be a valid ULID")
2277→	}
2278→
2279→	db.cmtx.Lock()
2280→	defer db.cmtx.Unlock()
2281→
2282→	db.mtx.RLock()
2283→	defer db.mtx.RUnlock()
2284→
2285→	for _, b := range db.blocks {
2286→		db.logger.Info("Snapshotting block", "block", b)
2287→
2288→		if err := b.Snapshot(dir); err != nil {
2289→			return fmt.Errorf("error snapshotting block: %s: %w", b.Dir(), err)
2290→		}
2291→	}
2292→	if !withHead {
2293→		return nil
2294→	}
2295→
2296→	mint := db.head.MinTime()
2297→	maxt := db.head.MaxTime()
2298→	head := NewRangeHead(db.head, mint, maxt)
2299→	// Add +1 millisecond to block maxt because block intervals are half-open: [b.MinTime, b.MaxTime).
2300→	// Because of this block intervals are always +1 than the total samples it includes.
2301→	if _, err := db.compactor.Write(dir, head, mint, maxt+1, nil); err != nil {
2302→		return fmt.Errorf("snapshot head block: %w", err)
2303→	}
2304→	return nil
2305→}

2300→	// Because of this block intervals are always +1 than the total samples it includes.
2301→	if _, err := db.compactor.Write(dir, head, mint, maxt+1, nil); err != nil {
2302→		return fmt.Errorf("snapshot head block: %w", err)
2303→	}
2304→	return nil
2305→}
