2307→// Querier returns a new querier over the data partition for the given time range.
2308→func (db *DB) Querier(mint, maxt int64) (_ storage.Querier, err error) {
2309→	var blocks []BlockReader
2310→
2311→	db.mtx.RLock()
2312→	defer db.mtx.RUnlock()
2313→
2314→	for _, b := range db.blocks {
2315→		if b.OverlapsClosedInterval(mint, maxt) {
2316→			blocks = append(blocks, b)
2317→		}
2318→	}
2319→
2320→	blockQueriers := make([]storage.Querier, 0, len(blocks)+1) // +1 to allow for possible head querier.
2321→
2322→	defer func() {
2323→		if err != nil {
2324→			// If we fail, all previously opened queriers must be closed.
2325→			for _, q := range blockQueriers {
2326→				// TODO(bwplotka): Handle error.
2327→				_ = q.Close()
2328→			}
2329→		}
2330→	}()
2331→
2332→	overlapsOOO := overlapsClosedInterval(mint, maxt, db.head.MinOOOTime(), db.head.MaxOOOTime())
2333→	var headQuerier storage.Querier
2334→	inoMint := max(db.head.MinTime(), mint)
2335→	if maxt >= db.head.MinTime() || overlapsOOO {
2336→		rh := NewRangeHead(db.head, mint, maxt)
2337→		var err error
2338→		headQuerier, err = db.blockQuerierFunc(rh, mint, maxt)
2339→		if err != nil {
2340→			return nil, fmt.Errorf("open block querier for head %s: %w", rh, err)
2341→		}
2342→
2343→		// Getting the querier above registers itself in the queue that the truncation waits on.
2344→		// So if the querier is currently not colliding with any truncation, we can continue to use it and still
2345→		// won't run into a race later since any truncation that comes after will wait on this querier if it overlaps.
2346→		shouldClose, getNew, newMint := db.head.IsQuerierCollidingWithTruncation(mint, maxt)
2347→		if shouldClose {
2348→			if err := headQuerier.Close(); err != nil {
2349→				return nil, fmt.Errorf("closing head block querier %s: %w", rh, err)
2350→			}
2351→			headQuerier = nil
2352→		}
2353→		if getNew {
2354→			rh := NewRangeHead(db.head, newMint, maxt)
2355→			headQuerier, err = db.blockQuerierFunc(rh, newMint, maxt)
2356→			if err != nil {
2357→				return nil, fmt.Errorf("open block querier for head while getting new querier %s: %w", rh, err)
2358→			}
2359→			inoMint = newMint
2360→		}
2361→	}
2362→
2363→	if overlapsOOO {
2364→		// We need to fetch from in-order and out-of-order chunks: wrap the headQuerier.
2365→		isoState := db.head.oooIso.TrackReadAfter(db.lastGarbageCollectedMmapRef)
2366→		headQuerier = NewHeadAndOOOQuerier(inoMint, mint, maxt, db.head, isoState, headQuerier)
2367→	}
2368→
2369→	if headQuerier != nil {
2370→		blockQueriers = append(blockQueriers, headQuerier)
2371→	}
2372→
2373→	for _, b := range blocks {
2374→		q, err := db.blockQuerierFunc(b, mint, maxt)
2375→		if err != nil {
2376→			return nil, fmt.Errorf("open querier for block %s: %w", b, err)
2377→		}
2378→		blockQueriers = append(blockQueriers, q)
2379→	}
2380→
2381→	return storage.NewMergeQuerier(blockQueriers, nil, storage.ChainedSeriesMerge), nil
2382→}
