2478→// Delete implements deletion of metrics. It only has atomicity guarantees on a per-block basis.
2479→func (db *DB) Delete(ctx context.Context, mint, maxt int64, ms ...*labels.Matcher) error {
2480→	db.cmtx.Lock()
2481→	defer db.cmtx.Unlock()
2482→
2483→	var g errgroup.Group
2484→
2485→	db.mtx.RLock()
2486→	defer db.mtx.RUnlock()
2487→
2488→	for _, b := range db.blocks {
2489→		if b.OverlapsClosedInterval(mint, maxt) {
2490→			g.Go(func(b *Block) func() error {
2491→				return func() error { return b.Delete(ctx, mint, maxt, ms...) }
2492→			}(b))
2493→		}
2494→	}
2495→	if db.head.OverlapsClosedInterval(mint, maxt) {
2496→		g.Go(func() error {
2497→			return db.head.Delete(ctx, mint, maxt, ms...)
2498→		})
2499→	}
2500→
2501→	return g.Wait()
2502→}
