2504→// CleanTombstones re-writes any blocks with tombstones.
2505→func (db *DB) CleanTombstones() (err error) {
2506→	db.cmtx.Lock()
2507→	defer db.cmtx.Unlock()
2508→
2509→	start := time.Now()
2510→	defer func() {
2511→		db.metrics.tombCleanTimer.Observe(time.Since(start).Seconds())
2512→	}()
2513→
2514→	cleanUpCompleted := false
2515→	// Repeat cleanup until there is no tombstones left.
2516→	for !cleanUpCompleted {
2517→		cleanUpCompleted = true
2518→
2519→		for _, pb := range db.Blocks() {
2520→			uids, safeToDelete, cleanErr := pb.CleanTombstones(db.Dir(), db.compactor)
2521→			if cleanErr != nil {
2522→				return fmt.Errorf("clean tombstones: %s: %w", pb.Dir(), cleanErr)
2523→			}
2524→			if !safeToDelete {
2525→				// There was nothing to clean.
2526→				continue
2527→			}
2528→
2529→			// In case tombstones of the old block covers the whole block,
2530→			// then there would be no resultant block to tell the parent.
2531→			// The lock protects against race conditions when deleting blocks
2532→			// during an already running reload.
2533→			db.mtx.Lock()
2534→			pb.meta.Compaction.Deletable = safeToDelete
2535→			db.mtx.Unlock()
2536→			cleanUpCompleted = false
2537→			if err = db.reloadBlocks(); err == nil { // Will try to delete old block.
2538→				// Successful reload will change the existing blocks.
2539→				// We need to loop over the new set of blocks.
2540→				break
2541→			}
2542→
2543→			// Delete new block if it was created.
2544→			for _, uid := range uids {
2545→				dir := filepath.Join(db.Dir(), uid.String())
2546→				if err := os.RemoveAll(dir); err != nil {
2547→					db.logger.Error("failed to delete block after failed `CleanTombstones`", "dir", dir, "err", err)
2548→				}
2549→			}
2550→
2551→			// This should only be reached if an error occurred.
2552→			return fmt.Errorf("reload blocks: %w", err)
2553→		}
2554→	}
2555→	return nil
2556→}
