 42→// NewMergeQuerier returns a new Querier that merges results of given primary and secondary queriers.
 43→// See NewFanout commentary to learn more about primary vs secondary differences.
 44→//
 45→// In case of overlaps between the data given by primaries' and secondaries' Selects, merge function will be used.
 46→func NewMergeQuerier(primaries, secondaries []Querier, mergeFn VerticalSeriesMergeFunc) Querier {
 47→	primaries = filterQueriers(primaries)
 48→	secondaries = filterQueriers(secondaries)
 49→
 50→	switch {
 51→	case len(primaries) == 0 && len(secondaries) == 0:
 52→		return noopQuerier{}
 53→	case len(primaries) == 1 && len(secondaries) == 0:
 54→		return primaries[0]
 55→	case len(primaries) == 0 && len(secondaries) == 1:
 56→		return &querierAdapter{newSecondaryQuerierFrom(secondaries[0])}
 57→	}
 58→
 59→	queriers := make([]genericQuerier, 0, len(primaries)+len(secondaries))
 60→	for _, q := range primaries {
 61→		queriers = append(queriers, newGenericQuerierFrom(q))
 62→	}
 63→	for _, q := range secondaries {
 64→		queriers = append(queriers, newSecondaryQuerierFrom(q))
 65→	}
 66→
 67→	concurrentSelect := len(secondaries) > 0
 68→
 69→	return &querierAdapter{&mergeGenericQuerier{
 70→		mergeFn:          (&seriesMergerAdapter{VerticalSeriesMergeFunc: mergeFn}).Merge,
 71→		queriers:         queriers,
 72→		concurrentSelect: concurrentSelect,
 73→	}}
 74→}
