 76→func filterQueriers(qs []Querier) []Querier {
 77→	ret := make([]Querier, 0, len(qs))
 78→	for _, q := range qs {
 79→		if _, ok := q.(noopQuerier); !ok && q != nil {
 80→			ret = append(ret, q)
 81→		}
 82→	}
 83→	return ret
 84→}
