100→	case len(primaries) == 0 && len(secondaries) == 1:
101→		return &chunkQuerierAdapter{newSecondaryQuerierFromChunk(secondaries[0])}
102→	}
103→
104→	queriers := make([]genericQuerier, 0, len(primaries)+len(secondaries))
105→	for _, q := range primaries {
106→		queriers = append(queriers, newGenericQuerierFromChunk(q))
107→	}
108→	for _, q := range secondaries {
109→		queriers = append(queriers, newSecondaryQuerierFromChunk(q))
110→	}
111→
112→	concurrentSelect := len(secondaries) > 0
113→
114→	return &chunkQuerierAdapter{&mergeGenericQuerier{
115→		mergeFn:          (&chunkSeriesMergerAdapter{VerticalChunkSeriesMergeFunc: mergeFn}).Merge,
116→		queriers:         queriers,
117→		concurrentSelect: concurrentSelect,
118→	}}
119→}
